DPDP_2025_RULES_OBLIGATIONS = [
    ("DPDP-S4", "Lawful processing grounds", "Process digital personal data only for lawful purposes with consent or for legitimate uses recognized by the DPDP Act, and document purpose-specific processing decisions.", "DPDP-DF", ["processing_purpose_register", "consent_or_legitimate_use_basis", "data_minimization_review"]),
    ("DPDP-S5-R3", "Clear notice before consent", "Provide an itemized, clear and plain-language notice before or with a consent request, including the personal data involved, the purpose of processing, rights available to the Data Principal, and grievance channels.", "DPDP-DF", ["consent_notice", "privacy_notice_version", "notice_language_review"]),
    ("DPDP-S6-R4", "Consent and withdrawal handling", "Maintain consent records and make withdrawal of consent as easy as giving consent, with downstream processing stopped unless another lawful basis applies.", "DPDP-DF", ["consent_records", "withdrawal_workflow", "processor_notification_records"]),
    ("DPDP-RULE-CM", "Consent Manager governance", "Where a Consent Manager is used, ensure it provides a transparent, interoperable platform for giving, managing, reviewing and withdrawing consent and meets India-presence and accountability expectations.", "DPDP-DF", ["consent_manager_due_diligence", "interoperability_evidence", "consent_manager_registration_records"]),
    ("DPDP-S8", "Data Fiduciary duties", "Implement reasonable security safeguards, ensure personal data accuracy where used for decisions or disclosure, honor processor accountability, publish contact details, and notify breaches as required.", "DPDP-DF", ["security_safeguards_documentation", "data_quality_procedure", "processor_contracts", "published_contact_details"]),
    ("DPDP-RULE-BREACH", "Personal data breach notification", "Notify affected Data Principals without delay using plain language that explains the breach, likely consequences, mitigation steps and contact details; notify the Data Protection Board as prescribed.", "DPDP-DF", ["breach_notification_playbook", "board_notification_records", "data_principal_notification_records"]),
    ("DPDP-RULE-CONTACT", "Personal data contact point", "Display clear contact information for questions and complaints about personal data, using a designated officer or Data Protection Officer where applicable.", "DPDP-DF", ["published_contact_details", "privacy_contact_mailbox", "complaint_intake_records"]),
    ("DPDP-RULE-PROCESSOR", "Processor accountability", "Ensure processors handle personal data only on behalf of the Data Fiduciary under documented instructions, safeguards, and accountability controls.", "DPDP-DF", ["processor_contracts", "processor_due_diligence", "processor_instruction_records"]),
    ("DPDP-RULE-RETENTION", "Storage limitation and erasure governance", "Erase personal data when consent is withdrawn, the purpose is no longer served, or retention is no longer necessary unless legal retention requirements apply.", "DPDP-DF", ["retention_policy", "erasure_jobs", "legal_hold_register"]),
    ("DPDP-RULE-BOARD", "Data Protection Board cooperation", "Maintain records and response procedures needed to cooperate with Data Protection Board inquiries, directions, breach reviews, and corrective measures.", "DPDP-DF", ["board_inquiry_playbook", "regulator_response_records", "corrective_action_register"]),
    ("DPDP-RULE-ACCOUNTABILITY", "Accountability record-keeping", "Maintain records evidencing compliance with consent, notice, rights-handling, security-safeguard, and grievance-management obligations, sufficient to demonstrate compliance to the Data Protection Board on inquiry.", "DPDP-DF", ["consent_audit_trail", "compliance_records_register", "board_inquiry_evidence_pack"]),
    ("DPDP-S9-R10", "Children's data and parental consent", "Before processing children's personal data, obtain verifiable parental or lawful guardian consent unless a rule-based exception applies for permitted services such as health, education or safety.", "DPDP-DF", ["age_assurance_process", "parental_consent_records", "children_data_exception_register"]),
    ("DPDP-S10-R11", "Persons with disability guardian consent", "Where a person with disability cannot legally act independently even with support, verify and record consent from the lawful guardian under applicable law.", "DPDP-DF", ["guardian_verification_records", "accessible_rights_workflow", "guardian_consent_records"]),
    ("DPDP-S11", "Right to access information", "Provide Data Principals with information about personal data being processed, processing activities and identities of Data Fiduciaries and processors where required.", "DPDP-DP", ["access_request_procedure", "processing_summary_responses", "processor_disclosure_records"]),
    ("DPDP-S12-R13", "Correction, completion, updating and erasure", "Enable Data Principals to request correction, completion, updating and erasure, and complete valid requests within prescribed timelines such as the ninety-day maximum referenced in the 2025 Rules explainer.", "DPDP-DP", ["correction_erasure_requests", "request_resolution_logs", "ninety_day_sla_tracking"]),
    ("DPDP-S13", "Grievance redressal", "Maintain an effective grievance redressal mechanism and resolve Data Principal grievances within prescribed timelines before escalation to the Data Protection Board.", "DPDP-DP", ["grievance_register", "resolution_timelines", "escalation_records"]),
    ("DPDP-S14", "Right to nominate", "Allow Data Principals to nominate another individual to exercise rights in the event of death or incapacity, and maintain records of nomination handling.", "DPDP-DP", ["nomination_process", "nominee_records", "rights_delegation_procedure"]),
    ("DPDP-SDF-1", "Data Protection Officer", "Significant Data Fiduciaries must appoint a Data Protection Officer based in India, reporting to the Board of Directors, as the point of contact for grievance redressal (DPDP Rules 2025, Rule 13).", "DPDP-SDF", ["dpo_appointment_letter", "dpo_contact_information", "dpo_india_residency_evidence"]),
    ("DPDP-SDF-2", "Independent data audit", "Significant Data Fiduciaries must undergo an independent data audit once every twelve months from the date of SDF notification (DPDP Rules 2025, Rule 13).", "DPDP-SDF", ["independent_audit_report", "auditor_appointment", "annual_audit_schedule"]),
    ("DPDP-SDF-3", "Algorithmic impact assessment", "Significant Data Fiduciaries must conduct periodic Data Protection Impact Assessments and algorithmic accountability reviews for high-risk technologies used to process personal data (DPDP Rules 2025, Rule 13).", "DPDP-SDF", ["dpia_records", "algorithmic_review_records", "ai_impact_assessment"]),
    ("DPDP-S16-R14", "Cross-border transfer restrictions", "Track transfers of personal data outside India and comply with Central Government restrictions for notified countries, territories or restricted data categories.", "DPDP-XBDR", ["transfer_mapping", "government_restriction_screening", "processor_location_register"]),
]
